def ref_fn_frm_fn(
    fn:str
    )->str:
    name_ = Path(fn).name
    mod_name = get_m_name(name_)
    pin_type = get_pin_type()[mod_name]
    try:
        if '2B' in pin_type:
            return 'ref_image_2B.png'
        elif '1B' in pin_type:
            return 'ref_image_1B.png'
        elif 'SMART' in pin_type:
            return 'ref_image_SMART.png'
    except Exception as e:
        print(e)
        print(f"Cannot find ref image name from {Path(fn).name}")

