def pin_count_from_fn(
        fn:str, # filename of mask file
    ):
    'get number of pins found from a mask filename'
    img = read_img(fn, cv=True,gray=True)
    
    lbl, _ = cv2.connectedComponents(img)
    return lbl - 1
